# ── TOOL INSTALLER ───────────────────────────────────────────────────────────
class ToolInstaller:
    APKTOOL_URL = "https://github.com/iBotPeaches/Apktool/releases/download/v3.0.2/apktool_3.0.2.jar"
    DEX2JAR_URL = "https://github.com/pxb1988/dex2jar/releases/download/v2.4/dex-tools-v2.4.zip"

    def __init__(self):
        os.makedirs(TOOLS_DIR, exist_ok=True)
        self.apktool_jar = os.path.join(TOOLS_DIR, "apktool.jar")
        self.dex2jar_dir = os.path.join(TOOLS_DIR, "dex2jar")
        self.tools_ready = False

    def _run(self, cmd, check=False):
        r = subprocess.run(cmd, shell=True, capture_output=True, text=True, timeout=180)
        if check and r.returncode != 0:
            logger.warning(f"[ToolInstaller] Command failed: {cmd}\n{r.stderr[:200]}")
        return r

    def install_system_deps(self):
        # Use sudo — bot runs as non-root on GitHub Actions
        # apt-get update first, then upgrade, then install
        self._run("sudo apt-get update -qq")
        self._run("sudo apt-get upgrade -y -qq")
        self._run(
            "sudo apt-get install -y -qq "
            "default-jdk zipalign apksigner wget unzip curl libsmali-java",
            check=True
        )
        # Try to upgrade apksigner to a version that supports V3 lineage
        # apksigner from apt is often old — try installing newer via sdkmanager
        # If sdkmanager not available — the graceful fallback in SigningLineageEngine
        # handles the unsupported option error and signs with standard v1+v2+v3
        try:
            # Check apksigner version
            r = self._run("apksigner version")
            version_str = r.stdout.strip() if r.returncode == 0 else ""
            logger.info(f"[ToolInstaller] apksigner version: {version_str}")
        except Exception:
            pass
        # NOTE: We do NOT copy smali.jar to TOOLS_DIR.
        # /usr/share/java/smali.jar is a LIBRARY jar (no Main-Class manifest).
        # Running it with java -jar fails with "no main manifest attribute".
        # The correct tool is the /usr/bin/smali BINARY (installed via
        # libsmali-java + java-wrappers packages) which calls org.jf.smali.Main
        # via the java-wrappers runtime (smali binary).

    def install_apktool(self):
        if not os.path.exists(self.apktool_jar):
            self._run(f"wget -q -O {self.apktool_jar} {self.APKTOOL_URL}")

    def install_dex2jar(self):
        if not os.path.exists(self.dex2jar_dir):
            zp = os.path.join(TOOLS_DIR, "dex2jar.zip")
            self._run(f"wget -q -O {zp} {self.DEX2JAR_URL}")
            self._run(f"unzip -q {zp} -d {self.dex2jar_dir}")
            self._run(f"chmod +x {self.dex2jar_dir}/dex-tools-v2.4/*.sh")

    def install_all(self):
        try:
            self.install_system_deps()
            self.install_apktool()
            self.install_dex2jar()
            self.tools_ready = True
            return True
        except Exception as e:
            logger.error(f"Tool install failed: {e}")
            return False

    def get_dex2jar(self):
        scripts = list(Path(self.dex2jar_dir).rglob("d2j-dex2jar.sh"))
        return str(scripts[0]) if scripts else None

    def get_jar2dex(self):
        scripts = list(Path(self.dex2jar_dir).rglob("d2j-jar2dex.sh"))
        return str(scripts[0]) if scripts else None


